import{_ as t,o as e,c as a,Q as o}from"./chunks/framework.b67c47e6.js";const m=JSON.parse('{"title":"API v2","description":"","frontmatter":{},"headers":[],"relativePath":"guide/api/index.md","filePath":"guide/api/index.md","lastUpdated":1773939149000}'),i={name:"guide/api/index.md"},r=o('<h1 id="api-v2" tabindex="-1">API v2 <a class="header-anchor" href="#api-v2" aria-label="Permalink to &quot;API v2&quot;">​</a></h1><p>The produuz.it REST API lets you automate design uploads, constructible management, report generation, and more from external systems.</p><nav class="table-of-contents"><ul><li><a href="#interactive-documentation">Interactive Documentation</a></li><li><a href="#authentication">Authentication</a></li><li><a href="#main-endpoint-groups">Main Endpoint Groups</a></li><li><a href="#common-workflows">Common Workflows</a></li><li><a href="#rate-limits">Rate Limits</a></li></ul></nav><h2 id="interactive-documentation" tabindex="-1">Interactive Documentation <a class="header-anchor" href="#interactive-documentation" aria-label="Permalink to &quot;Interactive Documentation&quot;">​</a></h2><p>The full API is documented through an interactive Swagger interface:</p><ul><li><strong>Swagger UI:</strong> <a href="https://back.produuz.it/api/v2/auth/login/?next=/api/v2/swagger/" target="_blank" rel="noreferrer">back.produuz.it/api/v2/swagger/</a></li><li><strong>OpenAPI Schema:</strong> Available at the same URL for importing into API clients.</li></ul><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>The API uses <strong>JWT (JSON Web Token)</strong> authentication with OTP (one-time password) verification.</p><ol><li><strong>Obtain a token</strong> — <code>POST /api/v2/my_user/token/</code> with your credentials and OTP code.</li><li><strong>Include the token</strong> — Add <code>Authorization: Bearer &lt;token&gt;</code> to all subsequent requests.</li><li><strong>Refresh the token</strong> — <code>POST /api/v2/my_user/token/refresh/</code> before the token expires.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For automated integrations, ask your admin to create an <strong>API Account</strong> in Company Settings. API accounts can authenticate without OTP.</p></div><h2 id="main-endpoint-groups" tabindex="-1">Main Endpoint Groups <a class="header-anchor" href="#main-endpoint-groups" aria-label="Permalink to &quot;Main Endpoint Groups&quot;">​</a></h2><table><thead><tr><th>Group</th><th>Base path</th><th>Description</th></tr></thead><tbody><tr><td><strong>Constructibles</strong></td><td><code>/api/v2/constructibles/</code></td><td>Designs, actuals (assemblies/modules), batches, parts</td></tr><tr><td><strong>Company</strong></td><td><code>/api/v2/company/</code></td><td>Projects, users, IFC parsing setups, API accounts</td></tr><tr><td><strong>Reports</strong></td><td><code>/api/v2/reports/</code></td><td>Report creation and status tracking</td></tr><tr><td><strong>Factories</strong></td><td><code>/api/v2/factories/</code></td><td>Production lines, stations, machines, triggers</td></tr><tr><td><strong>Cloud Storage</strong></td><td><code>/api/v2/cloudstorage/</code></td><td>File uploads and package management</td></tr><tr><td><strong>Logistics</strong></td><td><code>/api/v2/logistics/</code></td><td>Materials, stock, sizes, orders, delivery</td></tr><tr><td><strong>Records</strong></td><td><code>/api/v2/records/</code></td><td>Issues, production events</td></tr><tr><td><strong>Integrations</strong></td><td><code>/api/v2/integrations/</code></td><td>Webhooks</td></tr><tr><td><strong>User</strong></td><td><code>/api/v2/my_user/</code></td><td>Profile, authentication, settings</td></tr></tbody></table><h2 id="common-workflows" tabindex="-1">Common Workflows <a class="header-anchor" href="#common-workflows" aria-label="Permalink to &quot;Common Workflows&quot;">​</a></h2><p>For step-by-step API tutorials, see <a href="/tutorials/api/">Connecting to the API</a>:</p><ul><li><a href="/tutorials/api/post_designs/">Upload and create designs</a></li><li><a href="/tutorials/api/designs/">Fetch and filter designs</a></li><li><a href="/tutorials/api/constructibles/">Generate constructibles</a></li><li><a href="/tutorials/api/reports/">Generate reports and machine files</a></li></ul><h2 id="rate-limits" tabindex="-1">Rate Limits <a class="header-anchor" href="#rate-limits" aria-label="Permalink to &quot;Rate Limits&quot;">​</a></h2><p>The API enforces rate limits to ensure fair usage. If you receive a <code>429 Too Many Requests</code> response, wait before retrying.</p>',17),n=[r];function s(d,c,l,u,p,h){return e(),a("div",null,n)}const f=t(i,[["render",s]]);export{m as __pageData,f as default};
